#!/bin/bash
set -e
echo "FIX: consent gate + complete App.jsx"
mkdir -p src/modules/consent

cat << 'EOF' > src/modules/consent/consent-gate.jsx
import React,{useState} from "react";
const CK="tgd_consent_accepted",BK="tgd_consent_blocked";
function isBlocked(){try{const d=JSON.parse(localStorage.getItem(BK));if(!d)return false;if(Date.now()-new Date(d.blockedAt).getTime()<86400000)return true;localStorage.removeItem(BK);return false;}catch{return false;}}
function hasConsented(){try{return JSON.parse(localStorage.getItem(CK))?.accepted===true;}catch{return false;}}
export default function ConsentGate({children}){
  const[ok,setOk]=useState(hasConsented());
  const[no,setNo]=useState(isBlocked());
  const[name,setName]=useState("");
  const[detail,setDetail]=useState(false);
  if(no)return(<div className="min-h-screen bg-slate-50 flex items-center justify-center p-6"><div className="max-w-lg w-full text-center space-y-6"><p className="text-5xl">🔒</p><h1 className="text-2xl font-bold">Aplicacion bloqueada</h1><p className="text-slate-600">No se acepto el consentimiento. Podras volver en 24 horas.</p></div></div>);
  if(ok)return<>{children}</>;
  return(<div className="min-h-screen bg-slate-50 flex items-center justify-center p-6"><div className="max-w-2xl w-full space-y-6"><div className="text-center space-y-3"><p className="text-4xl">📋</p><h1 className="text-2xl font-bold">Consentimiento de uso</h1><p className="text-slate-600">El padre, madre o tutor legal debe aceptar antes de usar la app.</p></div><div className="rounded-2xl border bg-white p-6 space-y-4"><h2 className="font-bold text-lg">Sobre la aplicacion</h2><div className="space-y-3 text-sm text-slate-700"><div className="rounded-xl border bg-slate-50 p-4"><p className="font-semibold">Que es</p><p>App educativa para TEA/TGD/Asperger con LOMLOE, rutinas, apoyo emocional y herramientas familias.</p></div><div className="rounded-xl border bg-slate-50 p-4"><p className="font-semibold">Datos</p><p>NO recoge ni envia datos a servidores. Todo cifrado en dispositivo.</p></div><div className="rounded-xl border bg-slate-50 p-4"><p className="font-semibold">Privacidad</p><p>Sin telemetria, publicidad, rastreo. RGPD y LOPDGDD.</p></div><div className="rounded-xl border bg-slate-50 p-4"><p className="font-semibold">Menores 14</p><p>Requiere consentimiento tutor legal (LOPDGDD art. 7).</p></div></div><button onClick={()=>setDetail(!detail)} className="text-sm text-slate-500 underline">{detail?"Ocultar":"Ver detalle"}</button>{detail&&<div className="rounded-xl border bg-slate-50 p-4 text-xs text-slate-600 space-y-1"><p>1. Local-first.</p><p>2. AES-256-GCM + PBKDF2.</p><p>3. Sin email, telefono, IP.</p><p>4. Alias, no nombre.</p><p>5. Revocable desde Ajustes.</p><p>6. Sin IA internet.</p><p>7. Sin publicidad.</p><p>8. No sustituye profesionales.</p></div>}</div><div className="rounded-2xl border bg-white p-6 space-y-3"><h2 className="font-bold">Tutor legal</h2><input type="text" value={name} onChange={e=>setName(e.target.value)} placeholder="Nombre padre/madre/tutor" className="w-full rounded-xl border px-4 py-3"/></div><div className="flex flex-col sm:flex-row gap-4"><button disabled={!name.trim()} onClick={()=>{localStorage.setItem(CK,JSON.stringify({accepted:true,guardian:name.trim(),at:new Date().toISOString()}));setOk(true);}} className="flex-1 rounded-2xl px-6 py-4 bg-emerald-600 text-white font-bold text-lg disabled:opacity-40">ACEPTO</button><button onClick={()=>{localStorage.setItem(BK,JSON.stringify({blockedAt:new Date().toISOString()}));setNo(true);}} className="flex-1 rounded-2xl px-6 py-4 bg-rose-600 text-white font-bold text-lg">NO ACEPTO</button></div><p className="text-center text-xs text-slate-500">NO ACEPTO bloquea 24h.</p></div></div>);
}
EOF
echo "OK consent-gate.jsx"

cat << 'EOF' > src/App.jsx
import React,{useEffect,useState} from "react";
import ConsentGate from "./modules/consent/consent-gate.jsx";
import StageSelectorView from "./modules/stage-selector/stage-selector-view.jsx";
import {getStageById,getAvailableTabs,loadStageSelection,clearStageSelection} from "./core/stages-data.js";
import {resolverPerfil,listarComunidades} from "./core/curriculum-profiles.js";
import {getPinConfigMeta,generateTeacherPuk,setupPinSecurity,resetChildPinWithPuk} from "./core/pin-security.js";
import JournalView from "./modules/journal/journal-view.jsx";
import EmotionCompanion from "./modules/emotion/emotion-companion.jsx";

function Placeholder({name}){return<div className="rounded-2xl border bg-white p-8 text-center space-y-3"><p className="text-3xl">🚧</p><p className="font-bold text-lg">{name}</p><p className="text-slate-600">Contenido en desarrollo.</p></div>;}
function LazyModule({load,fallbackName,props}){const[C,setC]=useState(null);const[f,setF]=useState(false);useEffect(()=>{let ok=true;load().then(m=>{if(ok)setC(()=>m.default);}).catch(()=>{if(ok)setF(true);});return()=>{ok=false;};},[]);if(f)return<Placeholder name={fallbackName}/>;if(!C)return<div className="rounded-2xl border bg-white p-6 text-center">Cargando...</div>;return<C{...props}/>;}

function SecurityPanel(){const[meta,setMeta]=useState(getPinConfigMeta());const[cl,setCl]=useState("Alumno");const[cp,setCp]=useState("");const[tp,setTp]=useState(generateTeacherPuk());const[np,setNp]=useState("");const[up,setUp]=useState("");const[msg,setMsg]=useState("");async function configure(){try{await setupPinSecurity({childPin:cp,teacherPuk:tp,childLabel:cl});setMeta(getPinConfigMeta());setMsg("OK");}catch(e){setMsg(e.message);}}async function unlock(){try{await resetChildPinWithPuk(up,np);setMsg("PIN OK");}catch(e){setMsg(e.message);}}return<div className="space-y-4"><section className="rounded-2xl border bg-white p-5 space-y-3"><h3 className="text-lg font-bold">PIN+PUK</h3><div className="grid sm:grid-cols-3 gap-4"><input className="rounded-xl border px-3 py-2 w-full" value={cl} onChange={e=>setCl(e.target.value)} placeholder="Alumno"/><input className="rounded-xl border px-3 py-2 w-full" type="password" value={cp} onChange={e=>setCp(e.target.value)} placeholder="PIN"/><div className="flex gap-2"><input className="rounded-xl border px-3 py-2 w-full" value={tp} onChange={e=>setTp(e.target.value)}/><button onClick={()=>setTp(generateTeacherPuk())} className="rounded-xl border px-3 py-2 bg-white">Gen</button></div></div><button onClick={configure} className="rounded-2xl border px-4 py-3 bg-slate-900 text-white">Guardar</button>{meta&&<p className="text-sm text-slate-500">{meta.childLabel}</p>}</section><section className="rounded-2xl border bg-white p-5 space-y-3"><h4 className="font-semibold">Recuperar</h4><div className="grid sm:grid-cols-2 gap-4"><input className="rounded-xl border px-3 py-2 w-full" value={up} onChange={e=>setUp(e.target.value)} placeholder="PUK"/><input className="rounded-xl border px-3 py-2 w-full" type="password" value={np} onChange={e=>setNp(e.target.value)} placeholder="Nuevo PIN"/></div><button onClick={unlock} className="rounded-2xl border px-4 py-3 bg-emerald-600 text-white">Restablecer</button>{msg&&<div className="rounded-2xl border bg-sky-50 text-sky-900 p-4 text-sm">{msg}</div>}</section></div>;}

function AppContent(){const[sel,setSel]=useState(loadStageSelection());const[tab,setTab]=useState("inicio");const[com,setCom]=useState("madrid");const[tea,setTea]=useState(true);const[low,setLow]=useState(true);const[pin,setPin]=useState("");const[sn,setSn]=useState("Alumno");const[es,setEs]=useState(null);const perfil=resolverPerfil(com);const coms=listarComunidades();const stage=sel?getStageById(sel.stageId):null;const course=stage?stage.courses.find(c=>c.id===sel.courseId):null;const tabs=sel?getAvailableTabs(sel.stageId):[];useEffect(()=>{const m=getPinConfigMeta();if(m?.childLabel)setSn(m.childLabel);},[]);if(!sel)return<StageSelectorView onSelect={s=>setSel(s)}/>;const fr=low?"min-h-screen bg-slate-50 text-slate-900":"min-h-screen bg-gradient-to-br from-violet-50 via-white to-cyan-50 text-slate-900";const cp={teaMode:tea,lowStim:low,parentPin:pin};function renderTab(){switch(tab){case"inicio":return<div className="space-y-4"><section className="rounded-2xl border bg-white p-5 space-y-4"><h2 className="text-xl font-bold">Bienvenido</h2><p className="text-slate-600">{stage?.icon} {stage?.name} — {course?.label} ({sel.age} anios)</p><div className="grid sm:grid-cols-4 gap-4"><div className="space-y-2"><label className="block text-sm font-medium">Comunidad</label><select className="rounded-xl border px-3 py-2 w-full bg-white" value={com} onChange={e=>setCom(e.target.value)}>{coms.map(c=><option key={c} value={c}>{c}</option>)}</select></div><div className="space-y-2"><label className="block text-sm font-medium">Alumno</label><input className="rounded-xl border px-3 py-2 w-full" value={sn} onChange={e=>setSn(e.target.value)}/></div><button onClick={()=>setTea(!tea)} className={["rounded-2xl border p-3 text-left",tea?"bg-slate-900 text-white":"bg-white"].join(" ")}>TEA: {tea?"ON":"OFF"}</button><button onClick={()=>setLow(!low)} className={["rounded-2xl border p-3 text-left",low?"bg-slate-900 text-white":"bg-white"].join(" ")}>Baja est: {low?"ON":"OFF"}</button></div></section></div>;case"aprender":return<LazyModule load={()=>import("./modules/learning/quiz-view.jsx")} fallbackName="Aprender" props={{perfil:perfil.key,...cp,onStatsUpdate:setEs}}/>;case"tutor":return<LazyModule load={()=>import("./modules/emotional-tutor/emotional-tutor-view.jsx")} fallbackName="Tutor" props={{teaMode:tea}}/>;case"profesor":return<LazyModule load={()=>import("./modules/teacher/teacher-dashboard.jsx")} fallbackName="Profesor" props={{}}/>;case"redes":return<LazyModule load={()=>import("./modules/social/social-view.jsx")} fallbackName="Redes" props={cp}/>;case"retos":return<LazyModule load={()=>import("./modules/challenges/challenges-view.jsx")} fallbackName="Retos" props={cp}/>;case"historias":return<LazyModule load={()=>import("./modules/social/social-stories-view.jsx")} fallbackName="Historias" props={cp}/>;case"habitos":return<LazyModule load={()=>import("./modules/habits/habits-view.jsx")} fallbackName="Habitos" props={cp}/>;case"examenes":return<LazyModule load={()=>import("./modules/exams/exams-view.jsx")} fallbackName="Examenes" props={{perfil:perfil.key,perfilNombre:perfil.nombre,studentName:sn}}/>;case"juegos":return<LazyModule load={()=>import("./modules/games/games-view.jsx")} fallbackName="Juegos" props={{}}/>;case"tea":return<LazyModule load={()=>import("./modules/tea/tea-support-view.jsx")} fallbackName="TEA" props={{}}/>;case"rutinas":return<LazyModule load={()=>import("./modules/routines/routines-view.jsx")} fallbackName="Rutinas" props={cp}/>;case"emociones":return<EmotionCompanion/>;case"diario":return<JournalView parentPin={pin} teaMode={tea} lowStim={low}/>;case"familia":return<LazyModule load={()=>import("./modules/family/family-view.jsx")} fallbackName="Familia" props={cp}/>;case"informes":return<LazyModule load={()=>import("./modules/reports/reports-view.jsx")} fallbackName="Informes" props={{engineStats:es,studentName:sn,perfilNombre:perfil.nombre}}/>;case"seguridad":return<LazyModule load={()=>import("./modules/security/security-center.jsx")} fallbackName="Seguridad" props={{}}/>;case"ajustes":return<SecurityPanel/>;default:return<Placeholder name="?"/>;}};return<div className={fr}><div className="max-w-6xl mx-auto p-4 md:p-6 space-y-4"><header className="flex flex-wrap items-center justify-between gap-3"><div><h1 className="text-2xl md:text-3xl font-bold tracking-tight">TGD App educativa segura</h1><p className="text-sm text-slate-600">{stage?.icon} {stage?.name} — {course?.label} · {sel.age} anios · {perfil.nombre}</p></div><div className="flex flex-wrap gap-2">{es?.levelInfo&&<span className="rounded-2xl border bg-white px-3 py-2 text-sm">{es.levelInfo.icon} {es.levelInfo.name} · {es.levelInfo.totalPoints} pts</span>}<button onClick={()=>{clearStageSelection();setSel(null);setTab("inicio");}} className="rounded-2xl border px-3 py-2 bg-white hover:bg-slate-50 text-sm">Cambiar edad</button></div></header><nav className="flex flex-wrap gap-2">{tabs.map(t=><button key={t.key} onClick={()=>setTab(t.key)} className={["rounded-2xl border px-4 py-3 text-sm font-medium transition",tab===t.key?"bg-slate-900 text-white border-slate-900":"bg-white hover:bg-slate-50 border-slate-200"].join(" ")}>{t.label}</button>)}</nav>{renderTab()}</div></div>;}

export default function App(){return<ConsentGate><AppContent/></ConsentGate>;}
EOF
echo "OK App.jsx"
echo "DONE fix_app_complete.sh"
echo "IMPORTANTE: En navegador F12 Console: localStorage.clear()"
